import{_ as d,C as t,o as h,c as p,j as e,a as i,E as n,a3 as c}from"./chunks/framework.CVjg771q.js";const P=JSON.parse('{"title":"庄子·齐物论","description":"以天籁、彼是、齐物为核心，追问语言、判断与万物的真实关系。","frontmatter":{"title":"庄子·齐物论","description":"以天籁、彼是、齐物为核心，追问语言、判断与万物的真实关系。","category":"guide","aliases":["齐物论","庄子齐物论","zhuangzi chapter 02"],"source":["《庄子》","维基文库：庄子·齐物论"]},"headers":[],"relativePath":"daoism/texts/zhuang-zi/chapter-02.md","filePath":"daoism/texts/zhuang-zi/chapter-02.md","lastUpdated":1778126077000}'),m={name:"daoism/texts/zhuang-zi/chapter-02.md"};function u(x,a,b,g,f,_){const r=t("DaoReadingPrelude"),l=t("DaoOriginalReadingGroup"),o=t("DaoLineGuide"),s=t("DaoKeywordCards");return h(),p("div",null,[a[0]||(a[0]=e("h1",{id:"庄子·齐物论",tabindex:"-1"},[i("庄子·齐物论 "),e("a",{class:"header-anchor",href:"#庄子·齐物论","aria-label":'Permalink to "庄子·齐物论"'},"​")],-1)),n(r,{title:"从天籁到齐物，看清庄子如何拆解判断",summary:"齐物论是《庄子》内篇中最深、最绕的一篇。它不像逍遥游有那么多故事，而是大量使用反问、悖论和语言游戏来追问：我们对万物的判断到底有多可靠？这一篇读法上先不要急于追求「懂」，而是跟着庄子的节奏走，感受他如何一层一层拆掉我们关于是非、彼我、梦觉的固化判断。",points:[{label:"先看",text:"顺着原文走一遍，注意庄子的语言节奏：天籁→人籁→地籁→彼是→莫若以明→庄周梦蝶。"},{label:"再问",text:"庄子说「彼亦一是非，此亦一是非」，他在否定一切判断吗？还是在追问判断的边界？"},{label:"最后",text:"想一想：你有没有过「对错都不重要了」但反而更清醒的体验？"}],hint:"齐物论是庄子全书中哲学密度最高的篇章，建议分几次读，每次只消化一小段。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),n(l,{paragraphs:["南郭子綦隐几而坐，仰天而嘘，嗒焉似丧其耦。颜成子游立侍乎前，曰：「何居乎？形固可使如槁木，而心固可使如死灰乎？今之隐几者，非昔之隐几者也。」子綦曰：「偃，不亦善乎，而问之也！今者吾丧我，汝知之乎？女闻人籁而未闻地籁，女闻地籁而未闻天籁夫！」","子游曰：「敢问其方。」子綦曰：「夫大块噫气，其名为风。是唯无作，作则万窍怒呺。而独不闻之翏翏乎？山林之畏隹，大木百围之窍穴，似鼻，似口，似耳，似枅，似圈，似臼，似洼者，似污者；激者，謞者，叱者，吸者，叫者，譹者，宎者，咬者，前者唱于而随者唱喁。泠风则小和，飘风则大和，厉风济则众窍为虚。而独不见之调调、之刁刁乎？」子游曰：「地籁则众窍是已，人籁则比竹是已。敢问天籁。」子綦曰：「夫吹万不同，而使其自己也，咸其自取，怒者其谁邪！」","大知闲闲，小知间间；大言炎炎，小言詹詹。其寐也魂交，其觉也形开，与接为构，日以心斗。缦者，窖者，密者。小恐惴惴，大恐缦缦。其发若机栝，其司是非之谓也；其留如诅盟，其守胜之谓也；其杀若秋冬，以言其日消也；其溺之所为之，不可使复之也；其厌也如缄，以言其老洫也；近死之心，莫使复阳也。喜怒哀乐，虑叹变慹，姚佚启态；乐出虚，蒸成菌。日夜相代乎前，而莫知其所萌。已乎，已乎！旦暮得此，其所由以生乎！","非彼无我，非我无所取。是亦近矣，而不知其所为使。若有真宰，而特不得其眹。可行已信，而不见其形，有情而无形。百骸、九窍、六藏，赅而存焉，吾谁与为亲？汝皆说之乎？其有私焉？如是皆有为臣妾乎？其臣妾不足以相治乎？其递相为君臣乎？其有真君存焉？如求得其情与不得，无益损乎其真。一受其成形，不亡以待尽。与物相刃相靡，其行尽如驰，而莫之能止，不亦悲乎！终身役役而不见其成功，苶然疲役而不知其所归，可不哀邪！人谓之不死，奚益！其形化，其心与之然，可不谓大哀乎？人之生也，固若是芒乎？其我独芒，而人亦有不芒者乎？","夫随其成心而师之，谁独且无师乎？奚必知代而心自取者有之？愚者与有焉。未成乎心而有是非，是今日适越而昔至也。是以无有为有。无有为有，虽有神禹，且不能知，吾独且奈何哉！","夫言非吹也，言者有言，其所言者特未定也。果有言邪？其未尝有言邪？其以为异于鷇音，亦有辩乎，其无辩乎？道恶乎隐而有真伪？言恶乎隐而有是非？道恶乎往而不存？言恶乎存而不可？道隐于小成，言隐于荣华。故有儒墨之是非，以是其所非而非其所是。欲是其所非而非其所是，则莫若以明。","物无非彼，物无非是。自彼则不见，自知则知之。故曰彼出于是，是亦因彼。彼是，方生之说也。虽然，方生方死，方死方生；方可方不可，方不可方可；因是因非，因非因是。是以圣人不由，而照之于天，亦因是也。是亦彼也，彼亦是也。彼亦一是非，此亦一是非。果且有彼是乎哉？果且无彼是乎哉？彼是莫得其偶，谓之道枢。枢始得其环中，以应无穷。是亦一无穷，非亦一无穷也。故曰莫若以明。","以指喻指之非指，不若以非指喻指之非指也；以马喻马之非马，不若以非马喻马之非马也。天地一指也，万物一马也。可乎可，不可乎不可。道行之而成，物谓之而然。恶乎然？然于然。恶乎不然？不然于不然。物固有所然，物固有所可。无物不然，无物不可。故为是举莛与楹，厉与西施，恢恑憰怪，道通为一。"]}),n(o,{lines:[{label:"起",text:"南郭子綦「吾丧我」——齐物论的起始不在论理，而在忘掉自我这个起判断的中心。"},{label:"天籁",text:"人籁、地籁、天籁三问——天籁不是另一种声音，而是让万物各吹各的而不加干涉。"},{label:"心斗",text:"「大知闲闲，小知间间」至「近死之心莫使复阳」——描绘人被是非判断消耗殆尽的状态。"},{label:"真宰",text:"「若有真宰」至「其我独芒」——追问什么在主宰我们的喜怒哀乐？"},{label:"成心",text:"「随其成心而师之」——成见一旦成为判断标准，是非便由此而生。"},{label:"以明",text:"「道隐于小成，言隐于荣华」至「莫若以明」——不要用自己的是非去取消对方的是非，而是让事物在「明」中被看见。"},{label:"道枢",text:"「彼亦一是非，此亦一是非」至「道枢」——不是取消是非，而是在是非之上找到一个能「以应无穷」的枢纽。"},{label:"通一",text:"「道通为一」——一切差异，在道的层面，都可以贯通。这是齐物论的最高命题。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),n(s,{items:[{term:"吾丧我",pinyin:["wú","sàng","wǒ"],explanation:"我忘掉了自我。不是失去意识，而是放下那个执着分别的「小我」。这是齐物论的起点。"},{term:"天籁",pinyin:["tiān","lài"],explanation:"不是另一种声音，而是让万物各自发出自己声音的「使然之力」。天籁无声。"},{term:"成心",pinyin:["chéng","xīn"],explanation:"已经固化成型的心，即偏见、成见。庄子认为成心是一切是非之争的根源。"},{term:"以明",pinyin:["yǐ","míng"],explanation:"用「明」来看——不用自己的是非取消对方，而是让事物在光照中被看见。"},{term:"道枢",pinyin:["dào","shū"],explanation:"道的枢纽。站在环中，不偏不倚，可以应对无穷变化而不被是非所困。"},{term:"方生方死",pinyin:["fāng","shēng","fāng","sǐ"],explanation:"刚刚生，就刚刚死。万物变化不息，每一个判断在说出口的瞬间就已经过时。"},{term:"道通为一",pinyin:["dào","tōng","wéi","yī"],explanation:"在道的层面，一切差异都可以贯通。不是抹平差异，而是在更高维度上看见万物的相通。"},{term:"鷇音",pinyin:["kòu","yīn"],explanation:"雏鸟的叫声。庄子讥讽：人类自以为有意义的言说，和雏鸟的叫声有什么区别？"},{term:"莛",pinyin:["tíng"],explanation:"细小的草茎。与楹柱（大木）相对，象征小而卑微之物，但「道通为一」中它和楹柱没有不同。"},{term:"厉",pinyin:["lài"],explanation:"通「癞」，指丑女。与西施相对，说明美丑在道的层面也是相通的。"}]}),a[3]||(a[3]=c("",15))])}const k=d(m,[["render",u]]);export{P as __pageData,k as default};
